import React, { useState, useEffect, useRef } from "react";
import {
  BrowserRouter as Router,
  Route,
  Switch,
  NavLink
} from "react-router-dom";
import styled from "styled-components";
import Home from "./Home";
import Post from "./Post";
import Detail from "./Detail";
import Navigation from "./components/Navigation";
// import { library } from "@fortawesome/fontawesome-svg-core";
// import {
//   faAsterisk,
//   faSpinner,
//   faTable
// } from "@fortawesome/free-solid-svg-icons";
// library.add(faAsterisk, faSpinner, faTable);
import { faBars, faSearch } from "@fortawesome/free-solid-svg-icons";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";

const Container = styled.div`
  height: 100vh;
  width: 100vw;
  overflow-y: auto;

  @media (min-width: 1280px) {
    width: 1280px;
    display: grid;
    grid-template-columns: 1fr 250px;
    grid-template-rows: 50px 1fr 50px;

    nav {
      grid-area: 1/2/4/3;
      position: sticky;
    }
    header {
      grid-area: 1/1/2/2;
    }
    main {
      grid-area: 2/1/3/2;
    }
    footer {
      grid-area: 3/1/4/2;
    }
    .header-menu {
      visibility: hidden;
    }
  }
`;

const StyledHeaderCol = styled.div`
  width: 50px;
  height: 100%;
  display: flex;
  justify-content: center;
  align-items: center;
`;
const StyledHeaderTitle = styled.div`
  flex: 1;
  text-align: center;
  font-size: 24px;
  font-weight: 600;
`;
const Header = styled.header`
  height: 50px;
  border-bottom: 1px solid #e9ecef;
  display: flex;
  align-items: center;
  justify-content: space-between;
  z-index: 2;
`;

interface linkProps {
  issearch: string;
}
const StyledNavLink = styled(NavLink)<linkProps>`
  display: ${props => (props.issearch === "true" ? "none" : "flex")};
  align-items: center;
  justify-content: center;
  text-decoration: none;
  color: #000;
  height: 100%;
  width: 100%;
  &:focus,
  &:hover,
  &:visited,
  &:link,
  &:active {
    text-decoration: none;
  }
`;

const StyledInput = styled.input<linkProps>`
  border: 1px solid #e6e6e6;
  height: 60%;
  width: 250px;
  border-radius: 5px;
  font-size: 16px;
  display: ${props => (props.issearch === "true" ? "" : "none")};
`;

const StyledMain = styled.main`
  flex: 1;
  display: flex;
  flex-direction: column;
`;
function App() {
  const [hidden, setHidden] = useState(true);
  const [isSearch, setIsSearch] = useState(false);
  const refSearchInput = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isSearch) {
      if (refSearchInput.current) {
        refSearchInput.current.focus();
      }
    }
  }, [isSearch]);

  const navClick = () => {
    //e.stopPropagation();
    setHidden(!hidden);
  };

  const searchClick = () => {
    setIsSearch(!isSearch);
  };
  return (
    <Router basename={process.env.PUBLIC_URL}>
      <Container>
        <Header>
          <StyledHeaderCol onClick={searchClick}>
            <FontAwesomeIcon icon={faSearch} size="lg" />
          </StyledHeaderCol>
          <StyledHeaderTitle>
            <StyledNavLink
              issearch={isSearch.toString()}
              onClick={() => setHidden(true)}
              to="/"
              replace
            >
              Dryad
            </StyledNavLink>

            <StyledInput
              issearch={isSearch.toString()}
              ref={refSearchInput}
              type="text"
              placeholder="검색어를 입력하십시오."
            />
          </StyledHeaderTitle>
          <StyledHeaderCol onClick={navClick}>
            <FontAwesomeIcon icon={faBars} size="2x" />
          </StyledHeaderCol>
        </Header>
        <Navigation hidden={hidden} navClick={navClick} />
        <StyledMain>
          <Switch>
            <Route exact={true} path="/" component={Home} />
            <Route path="/posts/:category/:seq" component={Detail} />
            <Route path="/posts/:category" component={Post} />
          </Switch>
        </StyledMain>
      </Container>
    </Router>
  );
}

export default App;
